-- ============================================================================
-- 비료 상품 시드 데이터 (fertilizer_catalog.xlsx 업로드 파일 기준)
-- ============================================================================
-- 원본: 전단지 사진 58장을 OCR/육안 판독하여 정리한 "제품목록"·"사이트용 문안" 시트
-- 대상 DBMS: MySQL 8.0+ (utf8mb4)
--
-- [중요] 원본 요약 시트의 경고 그대로 전달합니다:
--   "전단지 사진 기반 정리이므로 실제 판매 전 제품 라벨·공시정보로 최종 검수하세요."
--   성분 수치도 전단지에 명확히 보이는 값만 입력되어 있어 결측이 많습니다.
--
-- [가격 안내] 계통계약가/표기가가 전단지에 실려 있던 상품(86개 중 29개)은 그 값을
-- 그대로 사용했고(price_source = 'catalog'), 나머지 57개는 포장 단위(kg/L/ml)와
-- 분류(완효성/유기질/미량요소 등)를 기준으로 한 단순 추정가로 채웠습니다
-- (price_source = 'estimated'). 실제 판매가로 그대로 쓰지 말고 검수 후 조정하세요.
--   - 대용량 입상비료(kg 단위): 1,000원/kg 기준 + 분류별 가중치
--     (완효성·기능성복합 +15% / 유기질·토양개량 -15% / 칼슘·미량요소·착색제 +35%)
--   - 소용량 액상·농축자재(ml/L 단위): 100ml 이하 45원/ml, 500ml 이하 33원/ml,
--     1L 이하 25원/ml, 그 이상 18원/ml + 위와 동일한 분류별 가중치
--   - 최종값은 3,000원~80,000원 범위로 clamp, 100원 단위 반올림
--
-- [컬럼 매핑] 제품목록 시트 컬럼 + 사이트용 문안 시트의 쇼핑몰 제목/bullet/설명/키워드를
-- 상품명 기준으로 병합했습니다. (사용법·주의/고객안내 컬럼은 제품목록의 사용량/희석배수,
-- 주의사항과 값이 동일하여 중복 저장하지 않았습니다.)
-- 고토(Mg)·규산(Si)·석회칼슘(Ca)·유기물 컬럼은 전단지에 "13~15", "70이상"처럼 범위/단위
-- 표기가 섞여 있어 VARCHAR로 저장했습니다. 질소(N)·인산(P)·칼리(K)·붕소(B)·유황(S)은
-- 모두 순수 숫자값만 확인되어 DECIMAL로 저장했습니다.
-- ============================================================================

CREATE TABLE IF NOT EXISTS fertilizer_products (
  id                  INT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
  product_code        VARCHAR(50)   NULL COMMENT '코드번호',
  name                VARCHAR(100)  NOT NULL COMMENT '상품명',
  brand               VARCHAR(100)  NULL COMMENT '제조/브랜드',
  category            VARCHAR(100)  NULL COMMENT '분류',
  form_type           VARCHAR(100)  NULL COMMENT '제형',
  usage_type          VARCHAR(100)  NULL COMMENT '용도',
  nitrogen_pct        DECIMAL(5,2)  NULL COMMENT '질소(N) %',
  phosphate_pct       DECIMAL(5,2)  NULL COMMENT '인산(P) %',
  potassium_pct       DECIMAL(5,2)  NULL COMMENT '칼리(K) %',
  magnesium_pct       VARCHAR(20)   NULL COMMENT '고토(Mg) % (범위 표기 포함)',
  boron_pct           DECIMAL(5,2)  NULL COMMENT '붕소(B) %',
  silica_pct          VARCHAR(20)   NULL COMMENT '규산(Si) % (범위 표기 포함)',
  calcium_pct         VARCHAR(20)   NULL COMMENT '석회/칼슘(Ca) % (범위 표기 포함)',
  sulfur_pct          DECIMAL(5,2)  NULL COMMENT '유황(S) %',
  organic_matter_pct  VARCHAR(20)   NULL COMMENT '유기물 % (범위 표기 포함)',
  package_unit        VARCHAR(30)   NULL COMMENT '포장 단위 (예: 20kg, 500cc)',
  recommended_crops   TEXT          NULL COMMENT '추천작물',
  usage_amount        VARCHAR(100)  NULL COMMENT '사용량/희석배수',
  main_effect         TEXT          NULL COMMENT '주요효과',
  precautions         TEXT          NULL COMMENT '주의사항',
  site_title          VARCHAR(200)  NULL COMMENT '쇼핑몰 제목(초안)',
  detail_bullets      TEXT          NULL COMMENT '상세페이지 핵심 bullet(초안)',
  description         TEXT          NULL COMMENT '상세 설명문(초안)',
  search_keywords     TEXT          NULL COMMENT '검색 키워드(초안)',
  source_photo        VARCHAR(100)  NULL COMMENT '원본 전단지 사진 파일명(검수용 추적자료)',
  price               INT UNSIGNED  NOT NULL COMMENT '판매가(원)',
  price_source        ENUM('catalog','estimated') NOT NULL DEFAULT 'estimated'
                       COMMENT '가격 출처: catalog=전단지 표기가, estimated=추정가',
  stock               INT UNSIGNED  NOT NULL DEFAULT 100 COMMENT '재고 수량(임의 기본값)',
  created_at          DATETIME      NOT NULL DEFAULT CURRENT_TIMESTAMP
) DEFAULT CHARSET = utf8mb4 COLLATE = utf8mb4_unicode_ci;

